const body = $input.first().json.body || $input.first().json;
const text = (body.text || body.instruction || '').trim();
const chatId = String(body.chatId || '7713811206');

if (!text) {
  return [{ json: { ok: false, error: 'text is required' } }];
}

const lower = text.toLowerCase();

const CODEX_KEYWORDS = ['\uD14C\uC2A4\uD2B8','\uB9AC\uD329\uD1A0\uB9C1','\uAD6C\uD604','\uC218\uC815','\uBC84\uADF8','\uD53D\uC2A4','e2e','lint','\uCF54\uB4DC \uC815\uB9AC','\uD0C0\uC785 \uCD94\uAC00'];
const CLAUDE_KEYWORDS = ['\uAE30\uD68D','\uC124\uACC4','\uBD84\uC11D','\uC804\uB7B5','\uC544\uD0A4\uD14D\uCC98','\uD300\uBBF8\uD305','PRD','\uB85C\uB4DC\uB9F5','\uC2E0\uADDC','\uD398\uC774\uC9C0'];

let codexScore = 0;
let claudeScore = 0;

for (const kw of CODEX_KEYWORDS) {
  if (lower.includes(kw.toLowerCase())) codexScore++;
}
for (const kw of CLAUDE_KEYWORDS) {
  if (lower.includes(kw.toLowerCase())) claudeScore++;
}

const worker = codexScore > claudeScore ? 'codex' : 'claude';
const workerLabel = worker === 'codex' ? 'Codex (\uAD6C\uD604/\uD14C\uC2A4\uD2B8)' : 'Claude Code (\uAE30\uD68D/\uC124\uACC4)';
const targetRoom = worker === 'codex' ? '-5198284773' : '-5043778307';

return [{ json: { ok: true, worker, workerLabel, prompt: text, chatId, targetRoom } }];

